    expect(res.status).toBe(400);
    expect(res.body.ok).toBe(false);
    expect(res.body.error).toMatch(/ancho_m|cant_paneles/);
  });

  test('400 cuando ancho_m es no numérico', async () => {
    const res = await request(app)
      .post('/api/cotizar')
      .send({
        escenario: 'solo_techo',
        familia: 'ISODEC_EPS',
        espesor_mm: 100,
